//批次下注 evolution
message NewBatchBetReq {
    repeated ChairBet chairBet = 1; // 下注
}

message ChairBet {
    optional sint32 chairId = 1; // 座位id
    repeated BetCoin betCoin = 2; 	//加注的籌碼類型與數量
}
message BetCoin {
    optional int32 bet = 1; //下注籌碼的面额
    optional int32 count = 2; //下注籌碼數量
}


message OperationReq { // 買保險/要求雙倍/要求分牌/要牌/要額外座位  command分辨
    optional sint32 chairId = 1; // 座位id
    optional int32 handId = 2; //下哪一副牌 分牌/要座位不需要這個參數
}

//下注
message BetReq {
    optional sint32 chairId = 1; // 座位id
    optional int32 bet = 2; 			//下注金额
}

message CardOrder{
    repeated sint32 cards = 1;
}



//批次下注
message BatchBetReq {
    optional sint32 chairId = 1; // 座位id
    repeated int32 bet = 2; 	//加注的籌碼類型與數量 int count*1000 + coin index, ex: coin index:1 下注19枚籌碼 bet = 19001
}

message CheatCodeReq {                      //預留給測試使用的指定發牌功能 用來指定這場補出的牌的順序  最多六列 依序為 莊家 座位1 2 3 4 5
    optional int32  playerOrder = 1;        //第幾個輪到玩家操作 0 - 4
    repeated int32 seatSet = 2;             //座位是否坐人 5個座位 0:有人 1:踢人 ex: [0,0,0,0,1] 第五個位置坐人 其他不影響
    repeated CardOrder cardOrder = 3;		//牌只需要給點數 1-13 花色由伺服器隨機分配
}

message LoginByID {
    optional int64 uid = 1;				//用户ID
    optional string token = 2; 			//用户session 由客户端登陆http后返回
    optional string version = 3; 		//用户版本

    optional int32 server = 7; // serverID（合并服用此字段区分进哪个服）
    optional int32 requestId = 8; // 用于识别重复请求唯一id（H5不用传）
}


message ErrorMessage {
    required sint32 code = 1; //错误代码 errorCode = 1; 1000时 表示当前在其他服中有正在进行的游戏
    optional string desc = 2; //错误消息	errorDescribe = 2;
    optional int32 serverId = 7; // 跳转的服务器Id
    optional string ip = 3; // 跳转的服务器ip
    optional int32 port = 4; // 跳转的端口
    optional int32 serverType = 5; // 跳转的服务器类型
    optional int32 subType = 6; // 跳转的房间类型（服务器子类型）
}

message UserMessage {
    optional int32 type = 1; // 游戏类型 1：捕鱼 2：斗地主（不会有该类型的通知） 3：炸金花 4：百人牛牛 5：抢庄牛牛
    optional int32 vip = 2; // 玩家VIP等级
    optional int32 cannon = 3; // 炮
    optional string nickName = 4; // 玩家名称
    optional int32 gold = 5; // 所赢金币
    optional int32 fishId = 6; // 打死鱼的id
    optional int32 cardType = 7; // 牌型 （炸金花：5 同花顺 6 豹子 | 百人牛牛、抢庄牛牛：11 牛牛 12 四炸 13 五花牛）
}

message NewUserMessage {
    optional int32 type = 1; // 游戏服务器类型
    optional int32 vip = 2; // 玩家VIP等级
    optional string nickName = 3; // 玩家名称
    optional int32 gold = 4; // 所赢金币

    optional int32 param1 = 5; // 自定义int参数1
    optional int32 param2 = 6; // 自定义int参数2
    optional int32 param3 = 7; // 自定义int参数3
    optional string param4 = 8; // 自定义string参数1
    optional string param5 = 9; // 自定义string参数2
}

message LeaveRes {
    optional sint32 chairId = 1;
}

message UpdateScoreRes {
    optional int64 userId = 1; // 玩家id
    optional int64 score = 2; // 当前金币数量
}

message UpdateScores {
    repeated UpdateScoreRes userScores = 1;
}

message SystemMessage {
    repeated sint32 type = 1; // 跑马灯播放的地方 -1：每个场景都播放 0：游戏大厅 1：捕鱼 2：斗地主 3：炸金花 4：百人牛牛 5：抢庄牛牛
    optional string content = 2; // 跑马灯内容
}

message OnlinePaybackRes {
    optional int64 userId = 1; // 用户ID
    optional int64 status = 2; // 状态。1=成功、0=失败
    optional int32 up_score = 3; // 金币增加数量（仅当status=1）
    optional int64 user_score= 4; // 加金币后，玩家最新余额（仅当status=1）
}



message UserData {
    optional int64 userId = 1; //用户id
    optional int32 ownChairId = 2; //玩家的主要座位号
    repeated sint32 chairId = 3; //玩家佔了哪幾個位置 座位号 莊家:0
    optional int32 status = 4; //状态: 2:准备(等待) 3:正在游戏 4:托管
    optional bool offline = 5; //玩家是否離線
    optional int64 score = 6; //金币
    optional string nickName = 7; //昵称
    optional int32 iconId = 8; //头像id
    optional int32 frameId = 9; //头像框id
    optional string userAddress = 10; // 玩家IP所属地区
    optional int32 vip = 11; // vip
    optional int32 lv = 12; // level
}

message RoomInfo {
    repeated int32 betConfig = 1;  // 各房間的籌碼級距
    optional int64 limitScore = 2;          // 遊戲開始最低金額
    optional int32 stage = 3; // 当前所处阶段：組局:0 下注:1 下注後:2 買保險:3 買保險後:4 發牌開始:5 開始輪詢發牌:6 結算:7
    optional int32 countdownTotal = 4; //此阶段倒计时初始值 (ms)
    optional int32 countdown = 5; // 倒计时 (ms)
    repeated UserData users = 6; // 房间中的玩家信息
    repeated sint32 chairAvailable = 7; //可以額外下注的空座位id列表
    repeated ChairHands chairCards = 8; // 每个位置上的牌（如果玩家是在遊戲進行階段进入房间）
    optional Deal deal = 9;
    optional Settles settles = 10;
    optional int32 firstChairIndex = 11; //起始玩家
    optional bool testMode = 12; //是否允許此玩家開啟測試模式
    optional int32 betLimitMuti = 13;// 注區上限的倍數(百分位) 實際上限為 底注 * betLimitMuti
    optional bool commingSettle = 14; //接著立即會有settle stage
    optional bool isBJ = 15; //莊家偷看牌是否真的是BJ
}

message NewStageInfo {
    optional int32 stage = 1;       //階段 組局:0 下注:1 下注後:2 買保險:3 買保險後:4 發牌開始:5 開始輪詢發牌:6 結算:7
    optional int32 countDown = 2; 		//当前阶段剩余时间倒计时
    repeated UserData users = 3; // 房间中的玩家信息
    repeated ChairHands chairCards = 4; // 每个位置上的牌
    optional int32 firstChairIndex = 5;    //起始玩家
    optional bool isBJ = 6; //莊家偷看牌是否真的是BJ
}

message ChairHands {
    optional sint32 chairId = 1;
    optional int32 insurance = 2;  //是否買保險 0: 未決定 1:買 2:不買
    repeated Hand handsList = 3;  //一個chair最多兩副牌
}

message Hand {
    repeated int32 bet = 1; //加注的籌碼類型與數量 int count*1000 + coin index, ex: coin index:1 下注19枚籌碼 bet = 19001
    repeated int32 cards = 2;  //0:蓋牌, 從1開始 依序為方塊Ace-King 梅花Ace-King 紅心Ace-King 黑桃Ace-King ex: 1:方塊Ace 13:方塊King 14:梅花Ace
    optional bool isDouble = 3;  //是否下雙倍
    optional int32 handType = 4; // (0:爆牌, 2-21:點數和, 22:過五關, 23:blackjack)
}

message Deal {  //發牌訊息
    optional sint32 chairId = 1;  //座位
    optional int32 handId = 2;  //1 or 2 一個位置可以分牌一次 所以有可能有兩副牌
    optional int32 countdownTotal = 3; //此阶段倒计时初始值 (ms)
    optional int32 countdown = 4; // 倒计时
    optional bool canSplit = 5; //可否分牌
    optional bool canDouble = 6;  //可否下雙倍
    optional int32 cards = 7;  //新發的牌
    optional Hand hand = 8;       //此副手牌
}

message ScoreDelta {
    optional int64 scoreDelta = 1;          // 此局產生的獎金
    optional int32 scoreDeltaSign = 2;      // 此局產生的獎金正負數；0：正數、1：負數
}
message Settle {
    optional sint32 chairId = 1;
    repeated ScoreDelta scoreDelta = 2; // 金币变化（> 0 税后赢钱 < 0 输钱） 一個位置可能會有兩副牌 輸贏分開顯示
    optional int32 lv = 3; // 玩家等级
}

message UserScoreDelta {
    optional int64 userId = 1; //用户id
    optional ScoreDelta scoreDelta = 2; //玩家輸贏分(總額 稅後)
}

message Settles {
    repeated Settle settle = 1;
    repeated UserScoreDelta userScoreDelta = 2; //玩家輸贏分(總額 稅後)
    optional Hand banksHand = 3;  //莊家手牌
    optional int32 isContinue = 4; // 是否继续 （默认为1继续，如果为0则需要客户端显示继续游戏按钮，点击继续后才准备）
    optional int32 countDown = 5; // 下一局倒计时
}

message OperationRes { //下注/買保險/要求雙倍/要求分牌/要牌/要新座位
    optional sint32 chairId = 1; // 座位id
    optional int64 userId = 2; //下操作或搶到座位的用户id
    optional int32 handId = 3; //下哪一副牌 分牌不需要這個參數
    repeated int32 bet = 4; //加注的籌碼類型與數量 int count*1000 + coin index, ex: coin index:1 下注19枚籌碼 bet = 19001
}

message BatchOperationRes { //批次下注
    optional int64 userId = 1; //下操作或搶到座位的用户id
    repeated OperationRes operationRes = 2;
}
